import type { SyntaxNodeRef } from '@lezer/common';

import type { ConvertedLezerNode } from '../../../../types/conversion-utils.js';
import type { FilterFieldBooleanNode } from '../../../../types/tree-nodes.js';
import { getTextFromRange } from '../../../get-text.js';

/**
 * Convert a boolean node.
 * @internal
 */
export function convertBoolean(
  node: SyntaxNodeRef,
  doc: string,
): ConvertedLezerNode<FilterFieldBooleanNode> {
  const { from, to } = node;
  const textValue = getTextFromRange(node, doc);

  const convertedNode: FilterFieldBooleanNode = {
    type: 'Boolean',
    textValue,
    value: textValue === 'true',
    range: { from, to },
  };

  return { convertedNode, errors: [] };
}
